import React, { useState, useEffect } from 'react';
import Tesseract from 'tesseract.js';
import { jsPDF } from "jspdf";
import { supabase } from './supabaseClient';
import { 
  UserCircle2, LayoutDashboard, Heart, ClipboardList, LogOut, Zap, Menu,
  Activity, FileText, Droplets, Brain, Beaker, Plus, X, FolderUp, Edit3
} from 'lucide-react';
import './Dashboard.css';

const Dashboard = ({ user, onLogout }) => {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAnalysing, setIsAnalysing] = useState(false);
  
  // Modals
  const [showClinicalModal, setShowClinicalModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [formData, setFormData] = useState({
    full_name: '', phone: '', address: '', gender: 'Male',
    age: '', weight: '', height: '', 
    bp_sys: '', bp_dia: '', sugar: '', creatine: '',
    smoking: 'No', alcohol: 'No', activity: 'Sedentary', sleep: '8', notes: ''
  });

  const getProfile = async () => {
    if (!user) return;
    try {
      let { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (data) {
        setProfile(data);
        setFormData(prev => ({ ...prev, ...data }));
      }
    } catch (err) { console.error("Profile Load Error:", err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    if (user) getProfile();
  }, [user]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const cleanNumericData = (data) => {
    return {
      ...data,
      age: data.age ? parseInt(data.age) : null,
      weight: data.weight ? parseFloat(data.weight) : null,
      height: data.height ? parseFloat(data.height) : null,
      bp_sys: data.bp_sys ? parseInt(data.bp_sys) : null,
      bp_dia: data.bp_dia ? parseInt(data.bp_dia) : null,
      sugar: data.sugar ? parseInt(data.sugar) : null,
      creatine: data.creatine ? parseFloat(data.creatine) : null,
    };
  };

  const handleSaveProfile = async () => {
    try {
      const sanitizedData = cleanNumericData({ id: user.id, ...formData });
      const { data } = await supabase.from('profiles').upsert(sanitizedData).select().single();
      setProfile(data);
      setFormData(prev => ({ ...prev, ...data }));
      setShowProfileModal(false);
      alert("Medical Profile Updated successfully!");
    } catch (err) { alert(err.message); }
  };

  const runAnalysisAndDownload = async () => {
    setIsAnalysing(true);
    let finalData = { ...formData };
    
    try {
      // OCR Parsing for document scans
      if (selectedFiles.length > 0) {
        const imageUrl = URL.createObjectURL(selectedFiles[0]);
        const { data: { text } } = await Tesseract.recognize(imageUrl, 'eng');
        URL.revokeObjectURL(imageUrl);
        
        const sugarMatch = text.match(/(?:glucose|sugar|glu)\D+(\d{2,3})/i);
        const creatineMatch = text.match(/(?:creatinine|crea)\D+(\d?\.?\d)/i);
        
        if (sugarMatch && !isNaN(parseInt(sugarMatch[1]))) finalData.sugar = parseInt(sugarMatch[1]);
        if (creatineMatch && !isNaN(parseFloat(creatineMatch[1]))) finalData.creatine = parseFloat(creatineMatch[1]);
      }

      const sanitizedData = cleanNumericData({ id: user.id, ...finalData });
      const { data: updatedProfile } = await supabase.from('profiles').upsert(sanitizedData).select().single();
      
      setProfile(updatedProfile);
      setFormData(prev => ({ ...prev, ...updatedProfile })); // Sync modal inputs

      // Generate Report PDF
      const doc = new jsPDF();
      doc.text("CLINICAL ANALYSIS REPORT", 20, 20);
      doc.text(`Patient: ${updatedProfile.full_name || 'N/A'}`, 20, 30);
      doc.text(`Cardiac BP: ${updatedProfile.bp_sys || '--'}/${updatedProfile.bp_dia || '--'}`, 20, 40);
      doc.text(`Sugar Level: ${updatedProfile.sugar || '--'}`, 20, 50);
      doc.text(`Creatinine: ${updatedProfile.creatine || '--'}`, 20, 60);
      doc.save(`Analysis_${Date.now()}.pdf`);

      setShowClinicalModal(false);
      setSelectedFiles([]); // Reset files
    } catch (err) { alert(err.message); } finally { setIsAnalysing(false); }
  };

  if (loading) return <div>Loading Interface...</div>;

  // --- DYNAMIC LOGIC & CALCULATIONS ---
  const weight = parseFloat(profile?.weight);
  const height = parseFloat(profile?.height);
  const bmiValue = (weight && height) ? (weight / (height / 100) ** 2).toFixed(1) : '--';
  const bmiStatus = bmiValue === '--' ? '--' : (bmiValue > 25 ? 'Overweight Range' : (bmiValue < 18.5 ? 'Underweight Range' : 'Normal Range'));

  const sysBP = parseFloat(profile?.bp_sys) || 0;
  const diaBP = parseFloat(profile?.bp_dia) || 0;
  const sugar = parseFloat(profile?.sugar) || 0;
  const creatine = parseFloat(profile?.creatine) || 0;

  // Risk Thresholds
  const isCardiacRisk = sysBP >= 140 || diaBP >= 90;
  const isRenalRisk = creatine >= 1.2 && creatine !== 0;
  const isMetabolicRisk = sugar >= 125 && sugar !== 0;
  const overallStatus = (isCardiacRisk || isRenalRisk || isMetabolicRisk) ? 'Elevated Risk' : 'Stable';

  return (
    <div className="dashboard-container">
      {/* HEADER */}
      <header className="dash-header">
        <div className="header-left">
          <span>CRM Analysis</span>
          <Heart fill="#10b981" color="#10b981" size={18} />
        </div>
        <div className="header-right">
          <span>Welcome, {profile?.full_name?.split(' ')[0] || 'User'}</span>
          <Menu className="menu-icon" size={24} />
        </div>
      </header>

      <div className="dash-main-wrapper">
        
        {/* LEFT SIDEBAR */}
        <aside className="dash-sidebar">
          <div className="sidebar-profile-card">
            <UserCircle2 className="sidebar-avatar" strokeWidth={1} />
            <div className="sidebar-name">{profile?.full_name || "Patient Name"}</div>
          </div>

          <div className="sidebar-nav-card">
            <button className="nav-item active"><LayoutDashboard size={18} /> Dashboard</button>
            <button className="nav-item" onClick={() => setShowClinicalModal(true)}><Heart size={18} /> Health &gt;</button>
            <button className="nav-item" onClick={() => setShowProfileModal(true)}><Edit3 size={18} /> Update Profile</button>
            <button className="nav-item nav-logout" onClick={onLogout}><LogOut size={16} /> Logout</button>
          </div>

          <div className="sidebar-integrity-card">
            <div className="integrity-header"><Zap size={16} fill="#5b4efb" color="#5b4efb"/> SYSTEM INTEGRITY</div>
            <div className="integrity-row"><span>Encryption</span><span className="status-green">● AES-256</span></div>
            <div className="integrity-row"><span>Cloud Sync</span><span className="status-green">● Active</span></div>
            <div className="integrity-row" style={{marginTop:'15px', color:'#94a3b8', fontSize:'0.7rem'}}>
              <FileText size={12}/> HIPAA Compliant Protocol
            </div>
          </div>
        </aside>

        {/* MAIN CONTENT */}
        <main className="dash-main-content">
          <div className="content-header"><h2>Clinical Overview</h2></div>
          
          {/* PURPLE BANNER */}
          <div className="clinical-banner">
            <div className="banner-name">{profile?.full_name || 'Patient Profile'}</div>
            <div className="banner-sub">ID: {user.id.slice(0,8)} | {profile?.age || '--'} Yrs | {profile?.gender || 'Male'}</div>
            <div className="banner-tags">
              <span className="b-tag">BP: {profile?.bp_sys || '--'}/{profile?.bp_dia || '--'}</span>
              <span className="b-tag">Sugar: {profile?.sugar || '--'} mg/dL</span>
              <span className="b-tag">Smoking: {profile?.smoking || 'No'}</span>
              <span className="b-tag">Activity: {profile?.activity || 'Sedentary'}</span>
              <span className="b-tag">Sleep: {profile?.sleep || '--'}h</span>
            </div>
          </div>

          {/* VITALS CARDS */}
          <div className="vitals-grid">
            <div className="vital-card">
              <div className="vital-title">Cardiac</div>
              <div className="vital-value-row">
                <Heart className="vital-icon" fill="#ef4444" color="#ef4444" />
                <div>
                  <div className="vital-num">{profile?.bp_sys || '--'}/{profile?.bp_dia || '--'}</div>
                  <div className="vital-unit">mmHg</div>
                </div>
              </div>
            </div>
            <div className="vital-card">
              <div className="vital-title">Renal</div>
              <div className="vital-value-row">
                <FileText className="vital-icon" color="#1e293b" />
                <div>
                  <div className="vital-num">{profile?.creatine || '--'}</div>
                  <div className="vital-unit">mg/dL</div>
                </div>
              </div>
            </div>
            <div className="vital-card">
              <div className="vital-title">Metabolic</div>
              <div className="vital-value-row">
                <Zap className="vital-icon" fill="#f59e0b" color="#f59e0b" />
                <div>
                  <div className="vital-num">{profile?.sugar || '--'}</div>
                  <div className="vital-unit">mg/dL</div>
                </div>
              </div>
            </div>
          </div>

          {/* SUMMARY ROW */}
          <div className="summary-grid">
            <div className="summary-card">
              <h4>Clinical Summary</h4>
              <div className="summary-value">{profile?.age || '--'} <span>Yrs</span></div>
              <div className="summary-status" style={{color: overallStatus === 'Stable' ? '#1e293b' : '#ef4444'}}>
                Status: <strong>{overallStatus}</strong>
              </div>
            </div>
            <div className="summary-card">
              <h4>Body Composition</h4>
              <div className="summary-value">{bmiValue} <span>BMI</span></div>
              <div className="summary-status">{bmiStatus}</div>
            </div>
          </div>

          {/* PATHOLOGICAL FORECAST */}
          <div className="section-title"><Activity size={18}/> Critical Pathological Forecast</div>
          <div className="forecast-grid">
            <div className="forecast-card">
              <div className="fc-header"><Heart size={16} color="#ef4444"/> Neuro-Cardiac Pathway</div>
              <ul className="fc-list">
                <li>Silent Heart Attack (Ischemia)</li>
                <li>Ischemic Stroke / Nerve Blocking</li>
                <li>Myocardial Infarction</li>
              </ul>
              <div className="fc-status">
                Status: {isCardiacRisk 
                  ? <span style={{color: '#ef4444'}}>High probability of acute events based on elevated arterial pressure.</span>
                  : "Low probability of acute neuro-cardiac events based on current arterial pressure."}
              </div>
            </div>
            <div className="forecast-card">
              <div className="fc-header"><Activity size={16} color="#f59e0b"/> Renal Failure Pathway</div>
              <ul className="fc-list">
                <li>Dialysis Dependency Condition</li>
                <li>Stage 3/4 Kidney Failure (CKD)</li>
                <li>Chronic Nephron Scarring</li>
              </ul>
              <div className="fc-status">
                Status: {isRenalRisk 
                  ? <span style={{color: '#f59e0b'}}>Elevated stress markers detected. Filtration capacity potentially reduced.</span> 
                  : "Normal filtration detected. Zero current markers for dialysis or renal failure."}
              </div>
            </div>
            <div className="forecast-card">
              <div className="fc-header"><Zap size={16} color="#10b981"/> Metabolic/Neural Pathway</div>
              <ul className="fc-list">
                <li>Diabetic Neuropathy</li>
                <li>Peripheral Nerve Blocking</li>
                <li>Microvascular Tissue Damage</li>
              </ul>
              <div className="fc-status">
                Status: {isMetabolicRisk 
                  ? <span style={{color: '#f59e0b'}}>Elevated glucose detected. High risk of metabolic nerve damage markers.</span> 
                  : "Glucose management is optimal; no active markers for metabolic nerve damage."}
              </div>
            </div>
          </div>

          {/* CLINICAL REFERENCE GUIDE */}
          <div className="section-title"><ClipboardList size={18}/> Clinical Reference Guide</div>
          <div className="ref-guide-card">
            <div className="ref-item">
              <div className="ref-head"><Heart size={14} color="#ef4444"/> Blood Pressure</div>
              <div className="ref-bar-wrapper">
                <div className="r-bar r-green"></div><div className="r-bar r-yellow"></div><div className="r-bar r-red"></div>
              </div>
              <div className="ref-labels"><span>Normal: &lt;120</span><span>High: 140+</span></div>
            </div>
            <div className="ref-item">
              <div className="ref-head"><Zap size={14} color="#f59e0b"/> Blood Glucose</div>
              <div className="ref-bar-wrapper">
                <div className="r-bar r-green"></div><div className="r-bar r-yellow"></div><div className="r-bar r-red"></div>
              </div>
              <div className="ref-labels"><span>Normal: 70-100</span><span>Prediabetes: 100-125</span></div>
            </div>
            <div className="ref-item">
              <div className="ref-head"><Activity size={14} color="#10b981"/> Creatinine</div>
              <div className="ref-bar-wrapper">
                <div className="r-bar r-green"></div><div className="r-bar r-yellow"></div><div className="r-bar r-red"></div>
              </div>
              <div className="ref-labels"><span>Normal: 0.7-1.3</span><span>Elevated: 1.3+</span></div>
            </div>
          </div>
        </main>

        {/* RIGHT PANEL */}
        <aside className="dash-right-panel">
          <div className="right-panel-card">
            <div className="rp-header"><Activity size={18}/> System Status</div>
            <div className="status-bar-row">
              <div className="sb-labels">
                <span>Cardiac</span>
                <span style={{color: isCardiacRisk ? '#ef4444' : '#10b981'}}>{isCardiacRisk ? 'ELEVATED' : 'OPTIMAL'}</span>
              </div>
              <div className="sb-track"><div className="sb-fill" style={{width: `${sysBP ? Math.min((sysBP / 180) * 100, 100) : 0}%`, background: isCardiacRisk ? '#ef4444' : '#10b981'}}></div></div>
            </div>
            <div className="status-bar-row">
              <div className="sb-labels">
                <span>Renal</span>
                <span style={{color: isRenalRisk ? '#f59e0b' : '#10b981'}}>{isRenalRisk ? 'STRESSED' : 'HEALTHY'}</span>
              </div>
              <div className="sb-track"><div className="sb-fill" style={{width: `${creatine ? Math.min((creatine / 2) * 100, 100) : 0}%`, background: isRenalRisk ? '#f59e0b' : '#10b981'}}></div></div>
            </div>
            <div className="status-bar-row">
              <div className="sb-labels">
                <span>Metabolic</span>
                <span style={{color: isMetabolicRisk ? '#f59e0b' : '#10b981'}}>{isMetabolicRisk ? 'WARNING' : 'STABLE'}</span>
              </div>
              <div className="sb-track"><div className="sb-fill" style={{width: `${sugar ? Math.min((sugar / 200) * 100, 100) : 0}%`, background: isMetabolicRisk ? '#f59e0b' : '#10b981'}}></div></div>
            </div>
          </div>

          <div className="rp-header" style={{marginTop: '2rem'}}><Brain size={18} color="#f59e0b"/> AI Health Forecasts</div>
          
          <div className="ai-forecast-item">
            <div className="ai-fc-head"><Heart size={14} color="#ef4444"/> Cardiac Outlook</div>
            <div className="ai-fc-desc">{isCardiacRisk ? "High vascular resistance detected. Immediate lifestyle intervention recommended." : "Vascular tension stable. High endurance predicted."}</div>
            <span className="ai-tip" style={{color: isCardiacRisk ? '#ef4444' : ''}}>TIP: {isCardiacRisk ? "CONSULT DOCTOR" : "CARDIO ROUTINE"}</span>
          </div>

          <div className="ai-forecast-item">
            <div className="ai-fc-head"><Zap size={14} color="#f59e0b"/> Metabolic Trend</div>
            <div className="ai-fc-desc">{isMetabolicRisk ? "High glucose processing strain. Monitor diet strictly." : "Glucose processing efficient. Stable energy predicted."}</div>
            <span className="ai-tip" style={{color: isMetabolicRisk ? '#f59e0b' : ''}}>TIP: {isMetabolicRisk ? "CUT SUGARS" : "BALANCE INTAKE"}</span>
          </div>

          <button className="btn-primary-new" onClick={() => setShowClinicalModal(true)}>
            <Plus size={16} style={{marginRight:'8px', verticalAlign:'middle'}}/> New Analysis
          </button>
        </aside>

      </div>

      {/* MODAL 1: CLINICAL INTELLIGENCE CENTER (New Analysis) */}
      {showClinicalModal && (
        <div className="modal-overlay">
          <div className="modal-container">
            <div className="modal-header">
              Clinical Intelligence Center
              <button className="modal-close" onClick={() => setShowClinicalModal(false)}><X size={20}/></button>
            </div>
            <div className="modal-body">
              {/* Col 1 */}
              <div>
                <div className="form-section-title"><Activity size={16}/> Vital Biomarkers</div>
                <div className="row-inputs">
                  <div className="input-group"><label>Systolic BP</label><input type="number" name="bp_sys" value={formData.bp_sys} onChange={handleInputChange} /></div>
                  <div className="input-group"><label>Diastolic BP</label><input type="number" name="bp_dia" value={formData.bp_dia} onChange={handleInputChange} /></div>
                </div>
                <div className="input-group"><label>Blood Sugar (mg/dL)</label><input type="number" name="sugar" value={formData.sugar} onChange={handleInputChange} /></div>
                <div className="input-group"><label>Creatinine (mg/dL)</label><input type="number" name="creatine" value={formData.creatine} onChange={handleInputChange} /></div>
              </div>
              {/* Col 2 */}
              <div>
                <div className="form-section-title"><Zap size={16}/> Lifestyle Factors</div>
                <div className="input-group">
                  <label>Smoking Status</label>
                  <select name="smoking" value={formData.smoking} onChange={handleInputChange}><option>No</option><option>Yes</option></select>
                </div>
                <div className="input-group">
                  <label>Physical Activity</label>
                  <select name="activity" value={formData.activity} onChange={handleInputChange}><option>Sedentary</option><option>Active</option></select>
                </div>
                <div className="input-group"><label>Sleep Schedule</label><input type="number" name="sleep" value={formData.sleep} onChange={handleInputChange} /></div>
              </div>
              {/* Col 3 */}
              <div>
                <div className="form-section-title"><FolderUp size={16}/> AI Document Scan</div>
                <div className="upload-box" onClick={() => document.getElementById('file-upload').click()}>
                  <FolderUp size={32} style={{marginBottom:'10px', color:'#5b4efb'}}/>
                  <div>Click to Upload Lab Report</div>
                  <small>{selectedFiles.length} files selected</small>
                  <input type="file" id="file-upload" hidden onChange={(e)=>setSelectedFiles([e.target.files[0]])} />
                </div>
                <div className="input-group" style={{marginTop:'20px'}}>
                  <label>Medical Notes</label>
                  <textarea name="notes" placeholder="Any new symptoms?" rows="3" onChange={handleInputChange} value={formData.notes}></textarea>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-save" onClick={runAnalysisAndDownload} disabled={isAnalysing}>{isAnalysing ? "Scanning & Saving..." : "Run Unified Analysis"}</button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL 2: PATIENT MEDICAL RECORD (Update Profile) */}
      {showProfileModal && (
        <div className="modal-overlay">
          <div className="modal-container">
            <div className="modal-header">
              Patient Medical Record
              <button className="modal-close" onClick={() => setShowProfileModal(false)}><X size={20}/></button>
            </div>
            <div className="modal-body">
              {/* Col 1 */}
              <div>
                <div className="form-section-title"><UserCircle2 size={16}/> Identity & Contact</div>
                <div className="input-group"><label>Full Name</label><input type="text" name="full_name" value={formData.full_name} onChange={handleInputChange} /></div>
                <div className="input-group"><label>Age</label><input type="number" name="age" value={formData.age} onChange={handleInputChange} /></div>
                <div className="input-group"><label>Phone Number</label><input type="text" name="phone" value={formData.phone} onChange={handleInputChange} /></div>
                <div className="input-group">
                  <label>Gender</label>
                  <select name="gender" value={formData.gender} onChange={handleInputChange}><option>Male</option><option>Female</option><option>Other</option></select>
                </div>
              </div>
              {/* Col 2 */}
              <div>
                <div className="form-section-title"><Zap size={16}/> Lifestyle Profile</div>
                <div className="input-group">
                  <label>Smoking</label>
                  <select name="smoking" value={formData.smoking} onChange={handleInputChange}><option>No</option><option>Yes</option></select>
                </div>
                <div className="input-group">
                  <label>Alcohol</label>
                  <select name="alcohol" value={formData.alcohol} onChange={handleInputChange}><option>No</option><option>Yes</option></select>
                </div>
                <div className="input-group">
                  <label>Physical Activity</label>
                  <select name="activity" value={formData.activity} onChange={handleInputChange}><option>Sedentary</option><option>Active</option></select>
                </div>
              </div>
              {/* Col 3 */}
              <div>
                <div className="form-section-title"><Activity size={16}/> Clinical History</div>
                <div className="row-inputs">
                  <div className="input-group"><label>Weight (KG)</label><input type="number" name="weight" value={formData.weight} onChange={handleInputChange} /></div>
                  <div className="input-group"><label>Height (CM)</label><input type="number" name="height" value={formData.height} onChange={handleInputChange} /></div>
                </div>
                <div className="input-group" style={{marginTop: '10px'}}>
                  <label>Health Problems (Comorbidities)</label>
                  <textarea name="comorbidities" rows="3" value={formData.comorbidities || ''} onChange={handleInputChange}></textarea>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn-save" onClick={handleSaveProfile}>Save Medical Profile</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
